example.code:
variable "project_id" { type = string }
variable "region"     { type = string; default = "us-central1" }
variable "job_name"   { type = string }
variable "image"      { type = string }
variable "task_count" { type = number; default = 1 }
variable "parallelism" { type = number; default = 1 }

resource "google_cloud_run_v2_job" "batch" {
  name     = var.job_name
  location = var.region

  template {
    task_count  = var.task_count
    parallelism = var.parallelism

    template {
      containers {
        image = var.image

        resources {
          limits = {
            cpu    = "2"
            memory = "4Gi"
          }
        }

        env {
          name  = "BUCKET"
          value = "my-data-bucket"
        }
      }

      max_retries = 3
      timeout     = "3600s"
    }
  }
}

resource "google_cloud_scheduler_job" "trigger" {
  name             = "${var.job_name}-trigger"
  region           = var.region
  schedule         = "0 6 * * *"
  time_zone        = "Europe/Kyiv"
  attempt_deadline = "320s"

  http_target {
    http_method = "POST"
    uri         = "https://${var.region}-run.googleapis.com/apis/run.googleapis.com/v1/namespaces/${var.project_id}/jobs/${var.job_name}:run"

    oauth_token {
      service_account_email = "scheduler-sa@${var.project_id}.iam.gserviceaccount.com"
    }
  }
}
